import org.apache.kafka.clients.consumer.ConsumerConfig;
import org.apache.kafka.clients.consumer.ConsumerRecord;
import org.apache.kafka.clients.consumer.ConsumerRecords;
import org.apache.kafka.clients.consumer.KafkaConsumer;
import org.apache.kafka.common.errors.WakeupException;
import org.apache.kafka.common.serialization.StringDeserializer;

import java.time.Duration;
import java.util.Collections;
import java.util.Properties;
import java.util.concurrent.atomic.AtomicBoolean;

/**
 * Consumes messages from the 'inventory-updates' Kafka topic and processes them idempotently.
 * Implements clean shutdown handling via WakeupException.
 */
public class InventoryConsumer {
    private final KafkaConsumer<String, String> consumer;
    private final AtomicBoolean closed = new AtomicBoolean(false);

    /**
     * Constructs an InventoryConsumer with the specified bootstrap servers.
     *
     * @param bootstrapServers comma-separated list of Kafka broker addresses
     */
    public InventoryConsumer(String bootstrapServers) {
        this.consumer = createKafkaConsumer(bootstrapServers);
    }

    /**
     * Creates a KafkaConsumer configured with ConsumerConfig constants.
     * Uses poll(Duration) API for efficient polling.
     */
    private KafkaConsumer<String, String> createKafkaConsumer(String bootstrapServers) {
        Properties props = new Properties();

        // Use ConsumerConfig constants instead of string literals
        props.put(ConsumerConfig.BOOTSTRAP_SERVERS_CONFIG, bootstrapServers);
        props.put(ConsumerConfig.GROUP_ID_CONFIG, "inventory-consumer-group");
        props.put(ConsumerConfig.CLIENT_ID_CONFIG, "inventory-consumer");
        props.put(ConsumerConfig.KEY_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class);
        props.put(ConsumerConfig.VALUE_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class);

        // Enable auto-commit for idempotent processing
        props.put(ConsumerConfig.ENABLE_AUTO_COMMIT_CONFIG, false);

        // Set the auto offset reset policy to earliest
        props.put(ConsumerConfig.AUTO_OFFSET_RESET_CONFIG, "earliest");

        // Maximum poll records for batch processing
        props.put(ConsumerConfig.MAX_POLL_RECORDS_CONFIG, 500);

        return new KafkaConsumer<>(props);
    }

    /**
     * Starts the consumer loop.
     * Subscribes to 'inventory-updates' topic and processes messages using poll(Duration).
     * Commits offsets synchronously after each batch for idempotent processing.
     */
    public void start() {
        consumer.subscribe(Collections.singleton("inventory-updates"));

        try {
            while (!closed.get()) {
                // Use poll(Duration) API (not deprecated poll(long))
                ConsumerRecords<String, String> records = consumer.poll(Duration.ofMillis(1000));

                // Process each record in the batch
                for (ConsumerRecord<String, String> record : records) {
                    processRecord(record);
                }

                // Commit offsets synchronously after processing batch
                // This ensures idempotent processing
                if (!records.isEmpty()) {
                    consumer.commitSync();
                }
            }
        } catch (WakeupException e) {
            // WakeupException is expected during shutdown
            if (!closed.get()) {
                throw e;
            }
        } finally {
            consumer.close();
        }
    }

    /**
     * Processes a single inventory update record.
     * This method should be idempotent to handle potential redelivery.
     *
     * @param record the consumer record to process
     */
    private void processRecord(ConsumerRecord<String, String> record) {
        // Idempotent processing: using message key as idempotency key
        String inventoryId = record.key();
        String updatePayload = record.value();

        System.out.printf("Processing inventory update - ID: %s, Payload: %s%n", inventoryId, updatePayload);

        // TODO: Implement idempotent business logic here
        // For example, use inventoryId as a unique identifier in database operations
        // to ensure the same message is processed exactly once even if consumed multiple times
    }

    /**
     * Gracefully shuts down the consumer.
     * This method is safe to call from a separate thread (e.g., shutdown hook).
     */
    public void shutdown() {
        if (closed.compareAndSet(false, true)) {
            consumer.wakeup();
        }
    }

    /**
     * Main entry point demonstrating usage.
     */
    public static void main(String[] args) {
        String bootstrapServers = "localhost:9092";
        InventoryConsumer consumer = new InventoryConsumer(bootstrapServers);

        // Register shutdown hook for clean shutdown
        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            System.out.println("Shutting down InventoryConsumer...");
            consumer.shutdown();
        }));

        // Start the consumer
        try {
            consumer.start();
        } catch (Throwable t) {
            System.err.println("Unexpected error in consumer: " + t.getMessage());
            t.printStackTrace();
        }
    }
}

